import jwt
import datetime
from typing import Dict, Optional

SECRET_KEY = "your-secret-key-change-this-in-production"
ALGORITHM = "HS256"
TOKEN_EXPIRATION_HOURS = 24


def generate_jwt_token(user_id: int, role: str, expires_in_hours: int = TOKEN_EXPIRATION_HOURS) -> str:
    """
    Generate a JWT token for user authentication.
    
    Args:
        user_id: The unique identifier of the user
        role: The role of the user (e.g., 'admin', 'user', 'guest')
        expires_in_hours: Token expiration time in hours (default: 24)
    
    Returns:
        JWT token as a string
    """
    expiration = datetime.datetime.utcnow() + datetime.timedelta(hours=expires_in_hours)
    
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': expiration,
        'iat': datetime.datetime.utcnow()
    }
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def verify_jwt_token(token: str) -> Optional[Dict]:
    """
    Verify and decode a JWT token.
    
    Args:
        token: The JWT token to verify
    
    Returns:
        Decoded payload as a dictionary if valid, None if invalid or expired
    """
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def refresh_jwt_token(token: str, expires_in_hours: int = TOKEN_EXPIRATION_HOURS) -> Optional[str]:
    """
    Refresh an existing JWT token with a new expiration time.
    
    Args:
        token: The current JWT token
        expires_in_hours: New expiration time in hours
    
    Returns:
        New JWT token as a string if valid, None if invalid
    """
    payload = verify_jwt_token(token)
    if payload:
        user_id = payload.get('user_id')
        role = payload.get('role')
        return generate_jwt_token(user_id, role, expires_in_hours)
    return None


if __name__ == "__main__":
    # Example usage
    user_id = 12345
